intent classify_tone(text: Text) -> Text {
    goal: tone_descriptor
}
pure fn count_words(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(x: Text) {
    s = "artificial intelligence is transforming industries"
    return join([to_text(count_words(s)), " words, ", classify_tone(s)], "")
}

intent feedback(score: Number) -> Text {
    goal: short_feedback_comment
}
pure fn avg(xs: [Number]) -> Number {
    total = 0
    for x in xs { total = total + x }
    return total / length(xs)
}
entry main(x: Text) {
    a = avg([82, 90, 75])
    return join([to_text(a), ": ", feedback(a)], "")
}

intent greet(name: Text) -> Text {
    goal: personalized_greeting
}
pure fn parse_names(s: Text) -> [Text] {
    return split(s, ",")
}
entry main(x: Text) {
    names = parse_names("Alice,Bob,Carol")
    results = []
    for n in names {
        results = append(results, greet(n))
    }
    return join(results, " | ")
}

intent compliment_length(n: Number) -> Text {
    goal: short_compliment_about_length
}
pure fn char_count(s: Text) -> Number {
    return length(split(s, ""))
}
entry main(x: Text) {
    s = "Hello, world!"
    n = char_count(s)
    return join([to_text(n), " chars: ", compliment_length(n)], "")
}
